-- Set lastSyncAt to 5 days ago so the next job run treats it as overdue and syncs immediately
UPDATE outreach_campaigns
SET lastSyncAt = UNIX_TIMESTAMP(DATE_SUB(NOW(), INTERVAL 5 DAY)) * 1000
WHERE id = 30001;

SELECT id, name, lastSyncAt, FROM_UNIXTIME(lastSyncAt/1000) as lastSyncHuman FROM outreach_campaigns WHERE id = 30001;

